import {normalizedComments} from '../fixtures'
import {ADD_COMMENT} from '../types'
import {arrToMap} from '../utils'

export default function (state = arrToMap(normalizedComments), action) {
    switch (action.type) {
        case ADD_COMMENT:
            return {
                ...state,
                [action.randomId]: {
                    ...action.payload.comment,
                    id: action.randomId
                }
            }
        default:
            return state
    }
}
